import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  CalendarIcon,
  ClockIcon,
  AlertTriangleIcon,
  BookOpenIcon,
  SendIcon,
  MenuIcon,
  UserIcon
} from 'lucide-react';
import { StatusBadge } from '../components/StatusBadge';
import { Modal } from '../components/Modal';

const SUBMITTED_REQUESTS = [
  {
    id: 'REQ-102',
    subject: 'Calculus Help',
    volunteer: 'Marcus Johnson',
    date: 'Oct 26, 2023 • 10:00 AM',
    status: 'pending'
  },
  {
    id: 'REQ-106',
    subject: 'Chemistry Lab',
    volunteer: 'Elena Rodriguez',
    date: 'Oct 29, 2023 • 1:00 PM',
    status: 'rejected'
  }
];

const ENROLLED_COURSES = [
  {
    id: 'REQ-101',
    subject: 'Python Tutoring',
    volunteer: 'Sarah Chen',
    date: 'Oct 24, 2023 • 2:00 PM',
    status: 'scheduled'
  },
  {
    id: 'REQ-103',
    subject: 'Biology Review',
    volunteer: 'Elena Rodriguez',
    date: 'Oct 20, 2023 • 4:30 PM',
    status: 'completed'
  },
  {
    id: 'REQ-104',
    subject: 'Physics Lab',
    volunteer: 'James Wilson',
    date: 'Oct 18, 2023 • 1:00 PM',
    status: 'completed'
  },
  {
    id: 'REQ-105',
    subject: 'Economics Prep',
    volunteer: 'David Kim',
    date: 'Oct 28, 2023 • 3:15 PM',
    status: 'accepted'
  }
];

export function StudentDashboard() {
  const [activeTab, setActiveTab] = useState('submitted');
  const [submittedRequests] = useState(SUBMITTED_REQUESTS);
  const [enrolledCourses] = useState(ENROLLED_COURSES);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isDisputeModalOpen, setIsDisputeModalOpen] = useState(false);
  const [selectedRequestId, setSelectedRequestId] = useState(null);
  const [disputeReason, setDisputeReason] = useState('');

  const openDisputeModal = (id) => {
    setSelectedRequestId(id);
    setDisputeReason('');
    setIsDisputeModalOpen(true);
  };

  const handleDisputeSubmit = (e) => {
    e.preventDefault();
    console.log(`Dispute filed for ${selectedRequestId}: ${disputeReason}`);
    setIsDisputeModalOpen(false);
    alert('Dispute submitted to Admin successfully.');
  };

  const contentVariants = {
    hidden: { opacity: 0, x: 10 },
    visible: { opacity: 1, x: 0, transition: { duration: 0.3 } },
    exit: { opacity: 0, x: -10, transition: { duration: 0.2 } }
  };

  const stats = [
    {
      label: 'Total Submitted',
      value: submittedRequests.length,
      icon: SendIcon,
      color: 'text-indigo-600',
      bg: 'bg-indigo-100'
    },
    {
      label: 'Pending',
      value: submittedRequests.filter((r) => r.status === 'pending').length,
      icon: ClockIcon,
      color: 'text-amber-600',
      bg: 'bg-amber-100'
    },
    {
      label: 'Rejected',
      value: submittedRequests.filter((r) => r.status === 'rejected').length,
      icon: AlertTriangleIcon,
      color: 'text-red-600',
      bg: 'bg-red-100'
    }
  ];

  const renderTimeline = (status) => {
    const steps = ['Submitted', 'Under Review', status === 'rejected' ? 'Rejected' : 'Accepted'];
    let currentStepIndex = 1;

    if (status === 'accepted' || status === 'scheduled') {
      currentStepIndex = 2;
    }
    if (status === 'rejected') {
      currentStepIndex = 2;
    }

    return (
      <div className="relative flex items-center justify-between w-full mt-6 mb-2 px-2">
        <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full h-1 bg-gray-200 rounded-full -z-10" />
        <div
          className="absolute left-0 top-1/2 transform -translate-y-1/2 h-1 bg-indigo-600 rounded-full -z-10 transition-all duration-500"
          style={{ width: `${(currentStepIndex / (steps.length - 1)) * 100}%` }}
        />

        {steps.map((step, index) => {
          const isCompleted = index < currentStepIndex;
          const isCurrent = index === currentStepIndex;
          const isRejected = step === 'Rejected';
          let dotClass = 'bg-gray-200 border-2 border-white';
          let textClass = 'text-gray-400';

          if (isCompleted) {
            dotClass = 'bg-indigo-600 border-2 border-white';
            textClass = 'text-indigo-600 font-medium';
          } else if (isCurrent) {
            if (isRejected) {
              dotClass = 'bg-red-500 ring-4 ring-red-100 border-2 border-white';
              textClass = 'text-red-600 font-bold';
            } else {
              dotClass = 'bg-indigo-600 ring-4 ring-indigo-100 border-2 border-white';
              textClass = 'text-indigo-700 font-bold';
            }
          }

          return (
            <div key={step} className="flex flex-col items-center relative z-10">
              <div className={`w-4 h-4 rounded-full ${dotClass}`} />
              <span className={`absolute top-6 text-xs whitespace-nowrap ${textClass}`}>{step}</span>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="flex flex-col md:flex-row min-h-[calc(100vh-73px)] bg-gray-50">
      <div className="md:hidden bg-white border-b border-gray-200 p-4 flex justify-between items-center sticky top-0 z-20">
        <span className="font-semibold text-gray-900">Student Dashboard</span>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 text-gray-500 hover:bg-gray-100 rounded-md">
          <MenuIcon className="w-5 h-5" />
        </button>
      </div>

      <div className={`${isMobileMenuOpen ? 'block' : 'hidden'} md:block w-full md:w-64 bg-white border-r border-gray-200 flex-shrink-0 md:sticky md:top-[73px] md:h-[calc(100vh-73px)] overflow-y-auto z-10`}>
        <div className="p-6 border-b border-gray-100">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold text-lg">S</div>
            <div>
              <h2 className="text-sm font-bold text-gray-900">Student Portal</h2>
              <p className="text-xs text-gray-500">Track your learning</p>
            </div>
          </div>
        </div>

        <nav className="p-4 space-y-1">
          <button
            onClick={() => {
              setActiveTab('submitted');
              setIsMobileMenuOpen(false);
            }}
            className={`w-full flex items-center px-3 py-2.5 text-sm font-medium rounded-md transition-colors ${
              activeTab === 'submitted'
                ? 'bg-indigo-50 text-indigo-700 border-l-2 border-indigo-600'
                : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900 border-l-2 border-transparent'
            }`}
          >
            <SendIcon className={`w-5 h-5 mr-3 ${activeTab === 'submitted' ? 'text-indigo-600' : 'text-gray-400'}`} />
            Submitted Requests
          </button>

          <button
            onClick={() => {
              setActiveTab('enrolled');
              setIsMobileMenuOpen(false);
            }}
            className={`w-full flex items-center px-3 py-2.5 text-sm font-medium rounded-md transition-colors ${
              activeTab === 'enrolled'
                ? 'bg-indigo-50 text-indigo-700 border-l-2 border-indigo-600'
                : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900 border-l-2 border-transparent'
            }`}
          >
            <BookOpenIcon className={`w-5 h-5 mr-3 ${activeTab === 'enrolled' ? 'text-indigo-600' : 'text-gray-400'}`} />
            Enrolled Courses
          </button>
        </nav>
      </div>

      <div className="flex-1 p-4 sm:p-6 lg:p-8 overflow-x-hidden">
        <AnimatePresence mode="wait">
          {activeTab === 'submitted' && (
            <motion.div key="submitted" variants={contentVariants} initial="hidden" animate="visible" exit="exit" className="max-w-4xl mx-auto">
              <div className="mb-8">
                <h1 className="text-2xl font-bold text-gray-900">Submitted Requests</h1>
                <p className="text-gray-500 mt-1">Track the status of your tutoring requests.</p>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
                {stats.map((stat, index) => (
                  <motion.div
                    key={stat.label}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: index * 0.1 }}
                    className="bg-white rounded-xl border border-gray-200 p-5 shadow-sm flex items-center space-x-4"
                  >
                    <div className={`p-3 rounded-lg ${stat.bg}`}>
                      <stat.icon className={`w-6 h-6 ${stat.color}`} />
                    </div>
                    <div>
                      <p className="text-sm font-medium text-gray-500">{stat.label}</p>
                      <p className="text-2xl font-bold text-gray-900">{stat.value}</p>
                    </div>
                  </motion.div>
                ))}
              </div>

              <div className="space-y-6">
                {submittedRequests.map((request) => (
                  <div key={request.id} className="bg-white rounded-xl border border-gray-200 p-6 shadow-sm flex flex-col">
                    <div className="flex justify-between items-start mb-6">
                      <div>
                        <h3 className="text-lg font-bold text-gray-900">{request.subject}</h3>
                        <p className="text-sm text-gray-500 flex items-center mt-1">
                          <UserIcon className="w-4 h-4 mr-1.5" /> Volunteer: {request.volunteer}
                        </p>
                        <p className="text-sm text-gray-500 flex items-center mt-1">
                          <CalendarIcon className="w-4 h-4 mr-1.5" /> Requested for: {request.date}
                        </p>
                      </div>
                      <StatusBadge status={request.status} />
                    </div>

                    <div className="mt-auto pt-4 pb-6 px-4 sm:px-8">{renderTimeline(request.status)}</div>
                  </div>
                ))}

                {submittedRequests.length === 0 && (
                  <div className="bg-white rounded-xl border border-gray-200 border-dashed p-10 text-center">
                    <SendIcon className="w-12 h-12 text-gray-300 mx-auto mb-3" />
                    <h3 className="text-lg font-medium text-gray-900">No requests submitted</h3>
                    <p className="text-gray-500 mt-1">Head over to Course Discovery to find a tutor.</p>
                  </div>
                )}
              </div>
            </motion.div>
          )}

          {activeTab === 'enrolled' && (
            <motion.div key="enrolled" variants={contentVariants} initial="hidden" animate="visible" exit="exit" className="max-w-5xl mx-auto">
              <div className="mb-8">
                <h1 className="text-2xl font-bold text-gray-900">Enrolled Courses</h1>
                <p className="text-gray-500 mt-1">Manage your active and completed sessions.</p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {enrolledCourses.map((course) => (
                  <motion.div
                    key={course.id}
                    layout
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden flex flex-col"
                  >
                    <div className="p-5 flex-1">
                      <div className="flex justify-between items-start mb-4">
                        <div className="flex items-center space-x-3">
                          <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold text-sm">
                            {course.volunteer
                              .split(' ')
                              .map((n) => n[0])
                              .join('')}
                          </div>
                          <div>
                            <h3 className="text-base font-bold text-gray-900">{course.volunteer}</h3>
                            <p className="text-sm text-gray-500 flex items-center mt-0.5">
                              <BookOpenIcon className="w-3.5 h-3.5 mr-1" /> {course.subject}
                            </p>
                          </div>
                        </div>
                        <StatusBadge status={course.status} />
                      </div>

                      <div className="flex items-center text-sm text-gray-600 bg-gray-50 p-3 rounded-lg border border-gray-100">
                        <CalendarIcon className="w-4 h-4 mr-2 text-gray-400" />
                        {course.date}
                      </div>
                    </div>

                    <div className="p-4 border-t border-gray-100 bg-gray-50/50 flex justify-end">
                      <motion.button
                        whileTap={{ scale: 0.98 }}
                        onClick={() => openDisputeModal(course.id)}
                        className="px-4 py-2 border border-indigo-200 text-indigo-600 bg-white hover:bg-indigo-50 rounded-lg text-sm font-medium transition-colors flex items-center"
                      >
                        <AlertTriangleIcon className="w-4 h-4 mr-1.5" /> File a Dispute
                      </motion.button>
                    </div>
                  </motion.div>
                ))}

                {enrolledCourses.length === 0 && (
                  <div className="col-span-full bg-white rounded-xl border border-gray-200 border-dashed p-10 text-center">
                    <BookOpenIcon className="w-12 h-12 text-gray-300 mx-auto mb-3" />
                    <h3 className="text-lg font-medium text-gray-900">No enrolled courses</h3>
                    <p className="text-gray-500 mt-1">Your accepted requests will appear here.</p>
                  </div>
                )}
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      <Modal isOpen={isDisputeModalOpen} onClose={() => setIsDisputeModalOpen(false)} title="File a Dispute">
        <form onSubmit={handleDisputeSubmit}>
          <div className="mb-4">
            <p className="text-sm text-gray-600 mb-4">
              If you experienced an issue with session <span className="font-semibold text-gray-900">{selectedRequestId}</span>, please provide details below.
              Our admin team will review your case.
            </p>
            <label htmlFor="dispute-reason" className="block text-sm font-medium text-gray-700 mb-1">
              Reason for Dispute
            </label>
            <textarea
              id="dispute-reason"
              rows={4}
              className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm resize-none"
              placeholder="Please describe what happened during or before the session..."
              value={disputeReason}
              onChange={(e) => setDisputeReason(e.target.value)}
              required
            />
          </div>
          <div className="flex justify-end space-x-3 mt-6">
            <button
              type="button"
              onClick={() => setIsDisputeModalOpen(false)}
              className="px-4 py-2 border border-gray-300 rounded-md shadow-sm text-sm font-medium text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 transition-colors"
            >
              Cancel
            </button>
            <motion.button
              whileTap={{ scale: 0.98 }}
              type="submit"
              className="px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 transition-colors"
            >
              Submit to Admin
            </motion.button>
          </div>
        </form>
      </Modal>
    </div>
  );
}
